def descriptor(rA, rB, rX, nA, nB, nX):
    # Compute the geometric mean of ionic radii to incorporate size compatibility
    size_mean = (rA * rB * rX) ** (1/3)
    # Calculate the normalized charge imbalance (sum of oxidation states divided by total ions)
    charge_imbalance = abs(nA + nB + nX) / 3
    # Calculate the ionic radius difference between A and the average B-X site
    radius_diff = abs(rA - (rB + rX) / 2)
    # Incorporate anion electronegativity trend (assuming higher electronegativity favors stability)
    # For simplicity, approximate electronegativities for common anions: O=3.44, F=3.98, Cl=3.16, Br=2.96, I=2.66
    electronegativities = {6: 3.44, 7: 3.98, 17: 3.16, 35: 2.96, 53: 2.66}
    X_atomic_number = round(rX)  # approximate atomic number from radius
    # Map radius to element (simplified, assuming typical ionic radii)
    if rX >= 1.9:
        en = electronegativities[53]  # I
    elif rX >= 1.7:
        en = electronegativities[35]  # Br
    elif rX >= 1.5:
        en = electronegativities[17]  # Cl
    elif rX >= 1.3:
        en = electronegativities[7]   # F
    else:
        en = electronegativities[6]   # O
    # Combine terms: stability increases with larger size mean, lower charge imbalance, and higher electronegativity
    return size_mean / (1 + charge_imbalance) * en / (radius_diff + 1e-3)
